53	// --- State Definition ---
54	struct State {
55	    std::vector<std::vector<int>> stacks;
56	    std::vector<std::pair<int, int>> box_pos; // {stack_idx, height_idx}
57	    long long energy_cost;
58	    std::vector<std::pair<int, int>> ops_history;
59	    int N_val;
60	    int M_val;
61	    bool record_ops_flag;
62	
63	    State() : energy_cost(0), N_val(0), M_val(0), record_ops_flag(true) {}
64	
65	    State(int N_in, int M_in, const std::vector<std::vector<int>>& initial_stacks_input, bool rec_ops = true)
66	        : energy_cost(0), N_val(N_in), M_val(M_in), record_ops_flag(rec_ops) {
67	        stacks.resize(M_val);
68	        for (int i = 0; i < M_val; ++i) {
69	            stacks[i].reserve(N_val + 20); 
70	        }
71	        box_pos.resize(N_val);
72	        if (record_ops_flag) {
73	            ops_history.reserve(N_val * 2 + 50); 
74	        }
75	
76	        for (int i = 0; i < M_val; ++i) {
77	            for (size_t j = 0; j < initial_stacks_input[i].size(); ++j) {
78	                int box_id = initial_stacks_input[i][j] - 1; // 0-indexed
79	                stacks[i].push_back(box_id);
80	                box_pos[box_id] = {i, (int)j};
81	            }
82	        }
83	    }
84	
85	    State(const State& other) = default;
86	    State& operator=(const State& other) = default;
87	    State(State&& other) noexcept = default;
88	    State& operator=(State&& other) noexcept = default;
89	
90	    double evaluate_destination_stack_choice(
91	        int current_target_box_val, // 0-indexed
92	        std::span<const int> block_to_move, // 0-indexed box values
93	        int dest_stack_idx) const { // 0-indexed
94	        const auto& dest_stack_content = stacks[dest_stack_idx];
95	        double current_score = 0;
96	
97	        if (dest_stack_content.empty()) {
98	            current_score -= HEURISTIC_EMPTY_STACK_BONUS_SCORE;
99	        } else {
100	            current_score += (double)dest_stack_content.size() * STACK_HEIGHT_PENALTY_FACTOR;
101	            int min_label_in_dest_stack = N_val; 
102	            for (int box_val_in_dest : dest_stack_content) {
103	                min_label_in_dest_stack = std::min(min_label_in_dest_stack, box_val_in_dest);
104	            }
105	            current_score -= (double)min_label_in_dest_stack * HEURISTIC_MIN_LABEL_IN_DEST_FACTOR;
106	        }
107	
108	        for (int box_in_dest : dest_stack_content) {
109	            if (box_in_dest > current_target_box_val && box_in_dest < current_target_box_val + HEURISTIC_LOOKAHEAD_WINDOW + 1) {
110	                current_score += HEURISTIC_COVER_CRITICAL_PENALTY_PER_BOX_ABOVE * block_to_move.size();
111	            }
112	        }
113	
114	        for (size_t i = 0; i < block_to_move.size(); ++i) {
115	            int box_in_block = block_to_move[i];
116	            if (box_in_block > current_target_box_val && box_in_block < current_target_box_val + HEURISTIC_LOOKAHEAD_WINDOW + 1) {
117	                int boxes_on_top_in_block = block_to_move.size() - 1 - i;
118	                current_score += HEURISTIC_COVER_CRITICAL_PENALTY_PER_BOX_ABOVE * boxes_on_top_in_block;
119	            }
120	        }
121	        return current_score;
122	    }
123	
124	    void apply_op1_move(int first_box_in_block_val, int num_moved_boxes, int dest_stack_idx) { // All 0-indexed
125	        int src_stack_idx = box_pos[first_box_in_block_val].first;
126	        int first_box_height_idx_in_src = box_pos[first_box_in_block_val].second;
127	
128	        auto& src_stack_vec = stacks[src_stack_idx];
129	        auto& dest_stack_vec = stacks[dest_stack_idx];
130	
131	        auto P_k_start_iter = src_stack_vec.begin() + first_box_height_idx_in_src;
132	        auto P_k_end_iter = src_stack_vec.begin() + first_box_height_idx_in_src + num_moved_boxes;
133	
134	        int old_dest_stack_height = dest_stack_vec.size();
135	        dest_stack_vec.insert(dest_stack_vec.end(),
136	                              std::make_move_iterator(P_k_start_iter),
137	                              std::make_move_iterator(P_k_end_iter));
138	
139	        for (int i = 0; i < num_moved_boxes; ++i) {
140	            int moved_box_val = dest_stack_vec[old_dest_stack_height + i];
141	            box_pos[moved_box_val] = {dest_stack_idx, old_dest_stack_height + i};
142	        }
143	
144	        src_stack_vec.erase(P_k_start_iter, P_k_end_iter);
145	
146	        energy_cost += (num_moved_boxes + 1);
147	        if (record_ops_flag) {
148	            ops_history.push_back({first_box_in_block_val + 1, dest_stack_idx + 1});
149	        }
150	    }
151	
152	    void apply_op2_carry_out(int target_box_val) { // 0-indexed
153	        int stack_idx = box_pos[target_box_val].first;
154	        stacks[stack_idx].pop_back();
155	        if (record_ops_flag) {
156	            ops_history.push_back({target_box_val + 1, 0});
157	        }
158	    }
159	};
