# EVOLVE-BLOCK-START
#include <iostream>
#include <vector>
#include <algorithm>
#include <chrono>
#include <random>
#include <climits>
#include <utility>

auto GLOBAL_START_TIME = std::chrono::steady_clock::now();
const double TIME_LIMIT = 1.90;

double elapsed() {
    return std::chrono::duration<double>(std::chrono::steady_clock::now() - GLOBAL_START_TIME).count();
}

struct Solver {
    int N, M;
    std::vector<std::vector<int>> initial_stacks;

    std::vector<std::vector<int>> stacks;
    std::vector<std::pair<int,int>> box_pos;
    std::vector<std::pair<int,int>> ops;
    long long energy;

    void init_state() {
        stacks = initial_stacks;
        box_pos.assign(N, {0,0});
        for (int i = 0; i < M; i++)
            for (int j = 0; j < (int)stacks[i].size(); j++)
                box_pos[stacks[i][j]] = {i, j};
        ops.clear();
        energy = 0;
    }

    void move_block(int box_v, int dest) {
        int src = box_pos[box_v].first;
        int h = box_pos[box_v].second;
        int num = (int)stacks[src].size() - h;

        int dest_h = (int)stacks[dest].size();
        for (int i = h; i < (int)stacks[src].size(); i++) {
            int b = stacks[src][i];
            stacks[dest].push_back(b);
            box_pos[b] = {dest, dest_h + (i - h)};
        }
        stacks[src].resize(h);

        energy += num + 1;
        ops.push_back({box_v + 1, dest + 1});
    }

    void carry_out(int box_v) {
        int src = box_pos[box_v].first;
        stacks[src].pop_back();
        ops.push_back({box_v + 1, 0});
    }

    double eval_dest(int src, int dest, const std::vector<int>& block, int current_target, double noise, std::mt19937& rng) {
        double score = 0;
        std::uniform_real_distribution<double> ndist(-noise, noise);

        score += (double)stacks[dest].size() * 2.5;

        if (stacks[dest].empty()) {
            score -= 40.0;
        }

        for (int b : stacks[dest]) {
            if (b > current_target && b < current_target + 20) {
                int urgency = current_target + 20 - b;
                score += 3.0 + 0.2 * urgency;
            }
        }

        for (int i = 0; i < (int)block.size(); i++) {
            int b = block[i];
            if (b > current_target && b < current_target + 15) {
                int boxes_above = (int)block.size() - 1 - i;
                score += 2.5 * boxes_above;
            }
        }

        if (noise > 0) score += ndist(rng);
        return score;
    }

    int choose_dest(int src, const std::vector<int>& block, int current_target, double noise, std::mt19937& rng) {
        int best_dest = -1;
        double best_score = 1e18;

        for (int d = 0; d < M; d++) {
            if (d == src) continue;
            double score = eval_dest(src, d, block, current_target, noise, rng);
            if (score < best_score) {
                best_score = score;
                best_dest = d;
            }
        }
        return best_dest;
    }

    long long solve_greedy(std::mt19937& rng, double noise = 0.0) {
        init_state();

        int k = 0;
        while (k < N) {
            while (k < N) {
                int src = box_pos[k].first;
                int h = box_pos[k].second;
                if (h != (int)stacks[src].size() - 1) break;
                carry_out(k);
                k++;
            }
            if (k >= N) break;

            int src = box_pos[k].first;
            int h = box_pos[k].second;
            int pile_size = (int)stacks[src].size() - 1 - h;

            int next_box = k + 1;
            bool should_split = false;

            if (next_box < N) {
                int next_src = box_pos[next_box].first;
                int next_h = box_pos[next_box].second;

                if (next_src == src && next_h > h) {
                    int boxes_above_next = (int)stacks[src].size() - 1 - next_h;
                    if (boxes_above_next > 0) {
                        should_split = true;
                    }
                }
            }

            if (should_split) {
                int next_h = box_pos[next_box].second;
                int upper_start = next_h + 1;

                int upper_first_box = stacks[src][upper_start];
                std::vector<int> upper_block(stacks[src].begin() + upper_start, stacks[src].end());
                int dest1 = choose_dest(src, upper_block, k, noise, rng);
                move_block(upper_first_box, dest1);

                int remaining_first_box = stacks[src][h + 1];
                std::vector<int> remaining_block(stacks[src].begin() + h + 1, stacks[src].end());
                int dest2 = choose_dest(src, remaining_block, k, noise, rng);
                move_block(remaining_first_box, dest2);

                carry_out(k);
                k++;
            } else {
                int first_above_k = stacks[src][h + 1];
                std::vector<int> block(stacks[src].begin() + h + 1, stacks[src].end());
                int dest = choose_dest(src, block, k, noise, rng);
                move_block(first_above_k, dest);
                carry_out(k);
                k++;
            }
        }
        return energy;
    }
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    GLOBAL_START_TIME = std::chrono::steady_clock::now();

    int N, M;
    std::cin >> N >> M;

    Solver solver;
    solver.N = N;
    solver.M = M;
    solver.initial_stacks.resize(M, std::vector<int>(N / M));
    for (int i = 0; i < M; i++)
        for (int j = 0; j < N / M; j++) {
            std::cin >> solver.initial_stacks[i][j];
            solver.initial_stacks[i][j]--;
        }

    std::mt19937 rng(42);

    long long best_energy = LLONG_MAX;
    std::vector<std::pair<int,int>> best_ops;

    solver.solve_greedy(rng, 0.0);
    if (solver.energy < best_energy) {
        best_energy = solver.energy;
        best_ops = solver.ops;
    }

    int iterations = 0;
    while (elapsed() < TIME_LIMIT) {
        double noise = 5.0 + 15.0 * std::uniform_real_distribution<double>(0,1)(rng);
        solver.solve_greedy(rng, noise);
        iterations++;
        if (solver.energy < best_energy) {
            best_energy = solver.energy;
            best_ops = solver.ops;
        }
    }

    for (const auto& op : best_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}
