    void init_state() {
        stacks = initial_stacks;
        box_pos.assign(N, {0,0});
        for (int i = 0; i < M; i++)
            for (int j = 0; j < (int)stacks[i].size(); j++)
                box_pos[stacks[i][j]] = {i, j};
        ops.clear();
        energy = 0;
    }

    void move_block(int box_v, int dest) {
        int src = box_pos[box_v].first;
        int h = box_pos[box_v].second;
        int num = (int)stacks[src].size() - h;

        int dest_h = (int)stacks[dest].size();
        for (int i = h; i < (int)stacks[src].size(); i++) {
            int b = stacks[src][i];
            stacks[dest].push_back(b);
            box_pos[b] = {dest, dest_h + (i - h)};
