        double score = 0;

        // Penalty for tall stacks - taller stacks mean more future moves
        score += stacks[dest].size() * w_height;

        // Bonus for empty stacks - strategic buffer
        if (stacks[dest].empty()) {
            score -= w_empty;
        }

        // Penalty for covering soon-needed boxes in destination
        for (int b : stacks[dest]) {
            if (b > current_target && b < current_target + 30) {
                double urgency = 30.0 / (b - current_target);
                score += w_cover * urgency;
            }
        }

        // Penalty for covering soon-needed boxes within the block itself
        // (the bottom of the block will be hardest to get later)
        for (int i = 0; i < (int)block.size(); i++) {
            int b = block[i];
            if (b > current_target && b < current_target + 30) {
                int boxes_above_in_block = (int)block.size() - 1 - i;
                double urgency = 30.0 / (b - current_target);
                score += w_sortedness * urgency * (1 + boxes_above_in_block);
            }
