    solver.solve_greedy_simple(rng, 0.0, w_height, w_cover, w_empty, w_sortedness);
    if (solver.energy < best_energy) {
        best_energy = solver.energy;
        best_ops = solver.ops;
    }

    // Random restarts with perturbation of weights and noise
    while (elapsed() < TIME_LIMIT) {
        std::uniform_real_distribution<double> wdist(0.5, 3.0);
        double rw_height = w_height * wdist(rng);
        double rw_cover = w_cover * wdist(rng);
        double rw_empty = w_empty * wdist(rng);
        double rw_sortedness = w_sortedness * wdist(rng);
        double noise = std::uniform_real_distribution<double>(2.0, 20.0)(rng);

        solver.solve_greedy_simple(rng, noise, rw_height, rw_cover, rw_empty, rw_sortedness);
        if (solver.energy < best_energy) {
            best_energy = solver.energy;
            best_ops = solver.ops;
