auto GLOBAL_START_TIME = std::chrono::steady_clock::now();
const double TIME_LIMIT = 1.90;

double elapsed() {
    return std::chrono::duration<double>(std::chrono::steady_clock::now() - GLOBAL_START_TIME).count();
}

struct State {
    int N, M;
    std::vector<std::vector<int>> stacks;
    std::vector<std::pair<int,int>> box_pos;
    long long energy;
    std::vector<std::pair<int,int>> ops;
    bool record_ops;
    int op_count;

    State() : N(0), M(0), energy(0), record_ops(false), op_count(0) {}

    void init(int n, int m, const std::vector<std::vector<int>>& init_stacks, bool rec) {
        N = n; M = m;
        stacks = init_stacks;
        box_pos.assign(N, {0,0});
        for (int i = 0; i < M; i++)
            for (int j = 0; j < (int)stacks[i].size(); j++)
                box_pos[stacks[i][j]] = {i, j};
        energy = 0;
        ops.clear();
        record_ops = rec;
        op_count = 0;
    }

    void move_block(int box_v, int dest) {
        int src = box_pos[box_v].first;
        int h = box_pos[box_v].second;
        int num = (int)stacks[src].size() - h;
        int dest_h = (int)stacks[dest].size();
        for (int i = h; i < (int)stacks[src].size(); i++) {
            int b = stacks[src][i];
            stacks[dest].push_back(b);
            box_pos[b] = {dest, dest_h + (i - h)};
        }
        stacks[src].resize(h);
        energy += num + 1;
        op_count++;
        if (record_ops) ops.push_back({box_v + 1, dest + 1});
    }

    void carry_out(int box_v) {
        int src = box_pos[box_v].first;
        stacks[src].pop_back();
        op_count++;
        if (record_ops) ops.push_back({box_v + 1, 0});
    }

    // Cost to extract box k (move pile above it + carry out)
    // Returns the number of boxes that need to be moved
    int extraction_cost(int k) const {
        int src = box_pos[k].first;
        int h = box_pos[k].second;
        int num_above = (int)stacks[src].size() - 1 - h;
        if (num_above == 0) return 0;
        return num_above + 1; // energy cost of move operation
    }
};

struct Solver {
    int N, M;
    std::vector<std::vector<int>> initial_stacks;

    // Greedy with 2-step lookahead
    long long solve_lookahead(std::mt19937& rng, double noise, std::vector<std::pair<int,int>>& result_ops) {
        State st;
        st.init(N, M, initial_stacks, true);

        int k = 0;
        while (k < N) {
            // Carry out consecutive available
            while (k < N) {
                int src = st.box_pos[k].first;
                int h = st.box_pos[k].second;
                if (h != (int)st.stacks[src].size() - 1) break;
                st.carry_out(k);
                k++;
                if (st.op_count >= 5000) { result_ops = st.ops; return st.energy; }
            }
            if (k >= N) break;

            int src = st.box_pos[k].first;
            int h = st.box_pos[k].second;
            int pile_size = (int)st.stacks[src].size() - 1 - h;

            int first_above = st.stacks[src][h + 1];

            // Try each destination, pick the one that minimizes cost(this move) + cost(next target extraction)
            int best_dest = -1;
            double best_score = 1e18;

            for (int d = 0; d < M; d++) {
                if (d == src) continue;

                // Cost of this move
                double cost = pile_size + 1;

                // Estimate cost for next few targets after this move
                // Simulate the move temporarily
                // We look at next target: where will k+1 be, and how costly to extract?
                int next_k = k + 1;
                // After moving block to d, check where next_k is
                if (next_k < N) {
                    int next_src = st.box_pos[next_k].first;
                    int next_h = st.box_pos[next_k].second;

                    if (next_src == src && next_h > h) {
                        // next_k is in the block being moved to d
                        // After move, it will be in stack d
                        // Position in d: stacks[d].size() + (next_h - (h+1))
                        int new_pos_in_d = (int)st.stacks[d].size() + (next_h - (h + 1));
                        int new_d_size = (int)st.stacks[d].size() + pile_size;
                        int num_above_next = new_d_size - 1 - new_pos_in_d;
                        if (num_above_next > 0) cost += num_above_next + 1;
                    } else if (next_src == d) {
                        // next_k is already in dest stack d, will be buried further
                        int num_above_next = (int)st.stacks[d].size() + pile_size - 1 - next_h;
                        if (num_above_next > 0) cost += num_above_next + 1;
                    } else {
                        // next_k is in another stack, unchanged
                        int num_above_next = (int)st.stacks[next_src].size() - 1 - next_h;
                        if (num_above_next > 0) cost += num_above_next + 1;
                    }
                }

                // Lookahead for k+2
                int next_k2 = k + 2;
                if (next_k2 < N) {
                    int n2_src = st.box_pos[next_k2].first;
                    int n2_h = st.box_pos[next_k2].second;

                    if (n2_src == src && n2_h > h) {
                        int new_pos = (int)st.stacks[d].size() + (n2_h - (h + 1));
                        int new_d_size = (int)st.stacks[d].size() + pile_size;
                        int num_above = new_d_size - 1 - new_pos;
                        if (num_above > 0) cost += (num_above + 1) * 0.5;
                    } else if (n2_src == d) {
                        int num_above = (int)st.stacks[d].size() + pile_size - 1 - n2_h;
                        if (num_above > 0) cost += (num_above + 1) * 0.5;
                    } else {
                        int num_above = (int)st.stacks[n2_src].size() - 1 - n2_h;
                        if (num_above > 0) cost += (num_above + 1) * 0.5;
                    }
                }

                // Lookahead for k+3..k+5 with decreasing weight
                for (int lookahead = 3; lookahead <= 5; lookahead++) {
                    int nk = k + lookahead;
                    if (nk >= N) break;
                    double weight = 0.3 / lookahead;
                    int nk_src = st.box_pos[nk].first;
                    int nk_h = st.box_pos[nk].second;

                    if (nk_src == src && nk_h > h) {
                        int new_pos = (int)st.stacks[d].size() + (nk_h - (h + 1));
                        int new_d_size = (int)st.stacks[d].size() + pile_size;
                        int num_above = new_d_size - 1 - new_pos;
                        if (num_above > 0) cost += (num_above + 1) * weight;
                    } else if (nk_src == d) {
                        int num_above = (int)st.stacks[d].size() + pile_size - 1 - nk_h;
                        if (num_above > 0) cost += (num_above + 1) * weight;
                    }
                }

                // Prefer empty stacks slightly
                if (st.stacks[d].empty()) cost -= 2.0;

                // Add noise
                if (noise > 0) {
                    std::uniform_real_distribution<double> ndist(-noise, noise);
                    cost += ndist(rng);
                }

                if (cost < best_score) {
                    best_score = cost;
                    best_dest = d;
                }
            }

            st.move_block(first_above, best_dest);
            if (st.op_count >= 5000) { result_ops = st.ops; return st.energy; }
            st.carry_out(k);
            k++;
            if (st.op_count >= 5000) { result_ops = st.ops; return st.energy; }
        }
        result_ops = st.ops;
        return st.energy;
    }
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    GLOBAL_START_TIME = std::chrono::steady_clock::now();

    int N, M;
    std::cin >> N >> M;

    Solver solver;
    solver.N = N;
    solver.M = M;
    solver.initial_stacks.resize(M, std::vector<int>(N / M));
    for (int i = 0; i < M; i++)
        for (int j = 0; j < N / M; j++) {
            std::cin >> solver.initial_stacks[i][j];
            solver.initial_stacks[i][j]--;
        }

    std::mt19937 rng(42);

    long long best_energy = LLONG_MAX;
    std::vector<std::pair<int,int>> best_ops;
    std::vector<std::pair<int,int>> tmp_ops;

    // Deterministic run
    long long e = solver.solve_lookahead(rng, 0.0, tmp_ops);
    if (e < best_energy) {
        best_energy = e;
        best_ops = tmp_ops;
    }

    // Random restarts with noise
    while (elapsed() < TIME_LIMIT) {
        double noise = std::uniform_real_distribution<double>(1.0, 15.0)(rng);
        e = solver.solve_lookahead(rng, noise, tmp_ops);
        if (e < best_energy) {
            best_energy = e;
            best_ops = tmp_ops;
        }
    }

    for (const auto& op : best_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }
    return 0;
}
