#include <cmath>
#include <array>

auto GLOBAL_START_TIME = std::chrono::steady_clock::now();
const double TIME_LIMIT = 1.92;
const int N_CONST = 200;
const int M_CONST = 10;

double elapsed() {
    return std::chrono::duration<double>(std::chrono::steady_clock::now() - GLOBAL_START_TIME).count();
}

struct FastState {
    std::array<std::vector<int>, M_CONST> stacks;
    std::array<int, N_CONST> box_stack;
    std::array<int, N_CONST> box_height;
    long long energy;

    void init(const std::vector<std::vector<int>>& init_stacks) {
        energy = 0;
        for (int i = 0; i < M_CONST; i++) {
            stacks[i] = init_stacks[i];
            for (int j = 0; j < (int)stacks[i].size(); j++) {
                box_stack[stacks[i][j]] = i;
                box_height[stacks[i][j]] = j;
            }
        }
    }

    void move_block(int box_v, int dest) {
        int src = box_stack[box_v];
        int h = box_height[box_v];
        int num = (int)stacks[src].size() - h;
        int dest_h = (int)stacks[dest].size();
        for (int i = h; i < h + num; i++) {
            int b = stacks[src][i];
            stacks[dest].push_back(b);
            box_stack[b] = dest;
            box_height[b] = dest_h + (i - h);
        }
        stacks[src].resize(h);
        energy += num + 1;
    }

    void carry_out(int box_v) {
        int src = box_stack[box_v];
        stacks[src].pop_back();
    }
};

// Plan: for each box k (0..N-1), plan[k] = dest stack to move the pile above k to
// If box k is already on top, plan[k] is ignored (we can set it to box's own stack)
struct Plan {
    std::array<int, N_CONST> dest;
};

long long evaluate_plan(const std::vector<std::vector<int>>& init_stacks, const Plan& plan) {
    FastState st;
    st.init(init_stacks);

    for (int k = 0; k < N_CONST; k++) {
        int src = st.box_stack[k];
        int h = st.box_height[k];
        int top = (int)st.stacks[src].size() - 1;
        if (h < top) {
            int first_above = st.stacks[src][h + 1];
            int d = plan.dest[k];
            if (d == src) d = (src + 1) % M_CONST;
            st.move_block(first_above, d);
        }
        st.carry_out(k);
    }
    return st.energy;
}

// Evaluate plan from position k_start with given intermediate state
long long evaluate_plan_suffix(FastState& st, const Plan& plan, int k_start) {
    for (int k = k_start; k < N_CONST; k++) {
        int src = st.box_stack[k];
        int h = st.box_height[k];
        int top = (int)st.stacks[src].size() - 1;
        if (h < top) {
            int first_above = st.stacks[src][h + 1];
            int d = plan.dest[k];
            if (d == src) d = (src + 1) % M_CONST;
            st.move_block(first_above, d);
        }
        st.carry_out(k);
    }
    return st.energy;
}

void simulate_prefix(const std::vector<std::vector<int>>& init_stacks, const Plan& plan, int k_end, FastState& out) {
    out.init(init_stacks);
    for (int k = 0; k < k_end; k++) {
        int src = out.box_stack[k];
        int h = out.box_height[k];
        int top = (int)out.stacks[src].size() - 1;
        if (h < top) {
            int first_above = out.stacks[src][h + 1];
            int d = plan.dest[k];
            if (d == src) d = (src + 1) % M_CONST;
            out.move_block(first_above, d);
        }
        out.carry_out(k);
    }
}

void generate_ops(const std::vector<std::vector<int>>& init_stacks, const Plan& plan,
                  std::vector<std::pair<int,int>>& ops) {
    FastState st;
    st.init(init_stacks);
    ops.clear();

    for (int k = 0; k < N_CONST; k++) {
        int src = st.box_stack[k];
        int h = st.box_height[k];
        int top = (int)st.stacks[src].size() - 1;
        if (h < top) {
            int first_above = st.stacks[src][h + 1];
            int d = plan.dest[k];
            if (d == src) d = (src + 1) % M_CONST;
            st.move_block(first_above, d);
            ops.push_back({first_above + 1, d + 1});
        }
        st.carry_out(k);
        ops.push_back({k + 1, 0});
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    GLOBAL_START_TIME = std::chrono::steady_clock::now();

    int N, M;
    std::cin >> N >> M;

    std::vector<std::vector<int>> initial_stacks(M);
    for (int i = 0; i < M; i++) {
        initial_stacks[i].resize(N / M);
        for (int j = 0; j < N / M; j++) {
            std::cin >> initial_stacks[i][j];
            initial_stacks[i][j]--;
        }
    }

    std::mt19937 rng(std::chrono::steady_clock::now().time_since_epoch().count());

    // Generate initial plan using greedy with lookahead heuristic
    auto make_greedy_plan = [&](double noise) -> Plan {
        Plan plan;
        FastState st;
        st.init(initial_stacks);

        for (int k = 0; k < N_CONST; k++) {
            int src = st.box_stack[k];
            int h = st.box_height[k];
            int top = (int)st.stacks[src].size() - 1;

            if (h == top) {
                plan.dest[k] = src;
                st.carry_out(k);
                continue;
            }

            int pile_size = top - h;
            int best_d = -1;
            double best_score = 1e18;

            for (int d = 0; d < M_CONST; d++) {
                if (d == src) continue;
                double score = 0;

                // Cost of this move
                score += pile_size + 1;

                // Check impact on future targets
                for (int look = k + 1; look < std::min(N_CONST, k + 25); look++) {
                    double weight = 1.0 / (look - k);
                    int ls = st.box_stack[look];
                    int lh = st.box_height[look];

                    if (ls == src && lh > h) {
                        // In the pile being moved to d
                        int new_h = (int)st.stacks[d].size() + (lh - h - 1);
                        int new_size = (int)st.stacks[d].size() + pile_size;
                        int above = new_size - 1 - new_h;
                        if (above > 0) score += (above + 1) * weight;
                    } else if (ls == d) {
                        // In dest stack, will be buried
                        int above = (int)st.stacks[d].size() + pile_size - 1 - lh;
                        if (above > 0) score += (above + 1) * weight;
                    }
                }

                if (st.stacks[d].empty()) score -= 3.0;
                score += st.stacks[d].size() * 0.3;

                if (noise > 0) {
                    score += std::uniform_real_distribution<double>(-noise, noise)(rng);
                }

                if (score < best_score) {
                    best_score = score;
                    best_d = d;
                }
            }

            plan.dest[k] = best_d;
            int first_above = st.stacks[src][h + 1];
            st.move_block(first_above, best_d);
            st.carry_out(k);
        }
        return plan;
    };

    // Generate initial plan
    Plan best_plan = make_greedy_plan(0.0);
    long long best_energy = evaluate_plan(initial_stacks, best_plan);

    // Try a few noisy greedy plans
    for (int i = 0; i < 20 && elapsed() < 0.2; i++) {
        double noise = std::uniform_real_distribution<double>(2.0, 15.0)(rng);
        Plan p = make_greedy_plan(noise);
        long long e = evaluate_plan(initial_stacks, p);
        if (e < best_energy) {
            best_energy = e;
            best_plan = p;
        }
    }

    // SA phase: perturb plan entries and accept/reject
    Plan current_plan = best_plan;
    long long current_energy = best_energy;

    double T_init = 50.0;
    double T_final = 0.1;
    double sa_start = elapsed();
    double sa_budget = TIME_LIMIT - sa_start - 0.02;

    // Checkpoint system: store intermediate states at regular intervals
    const int CHECKPOINT_INTERVAL = 20;
    const int NUM_CHECKPOINTS = N_CONST / CHECKPOINT_INTERVAL;
    std::vector<FastState> checkpoints(NUM_CHECKPOINTS + 1);

    auto rebuild_checkpoints = [&](const Plan& plan) {
        checkpoints[0].init(initial_stacks);
        checkpoints[0].energy = 0;
        FastState st;
        st.init(initial_stacks);
        for (int k = 0; k < N_CONST; k++) {
            int src = st.box_stack[k];
            int h = st.box_height[k];
            int top = (int)st.stacks[src].size() - 1;
            if (h < top) {
                int first_above = st.stacks[src][h + 1];
                int d = plan.dest[k];
                if (d == src) d = (src + 1) % M_CONST;
                st.move_block(first_above, d);
            }
            st.carry_out(k);
            if ((k + 1) % CHECKPOINT_INTERVAL == 0) {
                int ci = (k + 1) / CHECKPOINT_INTERVAL;
                if (ci <= NUM_CHECKPOINTS) {
                    checkpoints[ci] = st;
                }
            }
        }
    };

    rebuild_checkpoints(current_plan);
    int checkpoint_valid_for_current = 1; // checkpoints are valid for current_plan

    long long sa_iterations = 0;
    int last_rebuild = 0;

    while (true) {
        double now = elapsed();
        if (now >= TIME_LIMIT - 0.02) break;

        double progress = (now - sa_start) / sa_budget;
        if (progress > 1.0) break;
        double T = T_init * std::pow(T_final / T_init, progress);

        Plan new_plan = current_plan;
        int change_start = N_CONST;

        // Choose perturbation type
        double r = std::uniform_real_distribution<double>(0, 1)(rng);
        if (r < 0.4) {
            // Single point change
            int idx = std::uniform_int_distribution<int>(0, N_CONST - 1)(rng);
            new_plan.dest[idx] = std::uniform_int_distribution<int>(0, M_CONST - 1)(rng);
            change_start = idx;
        } else if (r < 0.8) {
            // Block change
            int idx = std::uniform_int_distribution<int>(0, N_CONST - 1)(rng);
            int len = std::uniform_int_distribution<int>(1, 15)(rng);
            change_start = idx;
            for (int i = 0; i < len; i++) {
                int ci = (idx + i) % N_CONST;
                new_plan.dest[ci] = std::uniform_int_distribution<int>(0, M_CONST - 1)(rng);
                change_start = std::min(change_start, ci);
            }
        } else {
            // Swap two plan entries
            int i1 = std::uniform_int_distribution<int>(0, N_CONST - 1)(rng);
            int i2 = std::uniform_int_distribution<int>(0, N_CONST - 1)(rng);
            std::swap(new_plan.dest[i1], new_plan.dest[i2]);
            change_start = std::min(i1, i2);
        }

        // Use checkpoint to evaluate faster
        int cp_idx = change_start / CHECKPOINT_INTERVAL;
        int sim_start = cp_idx * CHECKPOINT_INTERVAL;

        FastState eval_state;
        if (checkpoint_valid_for_current && cp_idx > 0) {
            eval_state = checkpoints[cp_idx];
            // But checkpoints are for current_plan, new_plan differs at change_start
            // If sim_start == cp_idx*CHECKPOINT_INTERVAL <= change_start, checkpoint is valid
            // because prefix is unchanged
            // Actually need to verify: new_plan[0..sim_start) == current_plan[0..sim_start)
            // Since we only changed at change_start >= sim_start, this holds
        } else {
            simulate_prefix(initial_stacks, new_plan, sim_start, eval_state);
        }

        // Simulate from sim_start to end
        // But we need to simulate from sim_start, not change_start, because
        // the checkpoint is at sim_start
        long long new_energy = evaluate_plan_suffix(eval_state, new_plan, sim_start);

        sa_iterations++;

        if (new_energy < current_energy) {
            current_energy = new_energy;
            current_plan = new_plan;
            checkpoint_valid_for_current = 0; // invalidate
            if (new_energy < best_energy) {
                best_energy = new_energy;
                best_plan = new_plan;
            }
            // Rebuild checkpoints periodically
            if (sa_iterations - last_rebuild > 500) {
                rebuild_checkpoints(current_plan);
                checkpoint_valid_for_current = 1;
                last_rebuild = sa_iterations;
            }
        } else {
            double delta = new_energy - current_energy;
            if (std::uniform_real_distribution<double>(0, 1)(rng) < std::exp(-delta / T)) {
                current_energy = new_energy;
                current_plan = new_plan;
                checkpoint_valid_for_current = 0;
                if (sa_iterations - last_rebuild > 500) {
                    rebuild_checkpoints(current_plan);
                    checkpoint_valid_for_current = 1;
                    last_rebuild = sa_iterations;
                }
            }
        }
    }

    // Output
    std::vector<std::pair<int,int>> ops;
    generate_ops(initial_stacks, best_plan, ops);
    for (const auto& op : ops) {
        std::cout << op.first << " " << op.second << "\n";
    }
    return 0;
