#include <iostream>
#include <vector>
#include <algorithm>
#include <chrono>
#include <random>
#include <climits>
#include <utility>
#include <cmath>

auto GLOBAL_START_TIME = std::chrono::steady_clock::now();
const double TIME_LIMIT = 1.92;

double elapsed() {
    return std::chrono::duration<double>(std::chrono::steady_clock::now() - GLOBAL_START_TIME).count();
}

struct State {
    int N, M;
    std::vector<std::vector<int>> stacks;
    std::vector<int> box_stack; // which stack
    std::vector<int> box_height; // height in that stack
    long long energy;
    std::vector<std::pair<int,int>> ops;
    bool record_ops;

    State() : N(0), M(0), energy(0), record_ops(false) {}

    void init(int n, int m, const std::vector<std::vector<int>>& init_stacks, bool rec) {
        N = n; M = m;
        stacks = init_stacks;
        box_stack.resize(N);
        box_height.resize(N);
        for (int i = 0; i < M; i++)
            for (int j = 0; j < (int)stacks[i].size(); j++) {
                box_stack[stacks[i][j]] = i;
                box_height[stacks[i][j]] = j;
            }
        energy = 0;
        ops.clear();
        record_ops = rec;
    }

    State copy_no_ops() const {
        State s;
        s.N = N; s.M = M;
        s.stacks = stacks;
        s.box_stack = box_stack;
        s.box_height = box_height;
        s.energy = energy;
        s.record_ops = false;
        return s;
    }

    void move_block(int box_v, int dest) {
        int src = box_stack[box_v];
        int h = box_height[box_v];
        int num = (int)stacks[src].size() - h;
        int dest_h = (int)stacks[dest].size();
        for (int i = h; i < (int)stacks[src].size(); i++) {
            int b = stacks[src][i];
            stacks[dest].push_back(b);
            box_stack[b] = dest;
            box_height[b] = dest_h + (i - h);
        }
        stacks[src].resize(h);
        energy += num + 1;
        if (record_ops) ops.push_back({box_v + 1, dest + 1});
    }

    void carry_out(int box_v) {
        int src = box_stack[box_v];
        stacks[src].pop_back();
        if (record_ops) ops.push_back({box_v + 1, 0});
    }

    // Simple greedy destination choice for simulation
    int greedy_dest(int src, int current_target) const {
        int best_dest = -1;
        double best_score = 1e18;
        for (int d = 0; d < M; d++) {
            if (d == src) continue;
            double score = stacks[d].size() * 2.0;
            if (stacks[d].empty()) score -= 30.0;
            for (int b : stacks[d]) {
                if (b > current_target && b < current_target + 20) {
                    score += 5.0;
                }
            }
            if (score < best_score) {
                best_score = score;
                best_dest = d;
            }
        }
        return best_dest;
    }

    // Simulate extracting boxes from k_start to k_end using greedy
    long long simulate_greedy(int k_start, int k_end) {
        long long start_energy = energy;
        for (int k = k_start; k < k_end; k++) {
            // Carry out if on top
            while (k < k_end) {
                int src = box_stack[k];
                int h = box_height[k];
                if (h != (int)stacks[src].size() - 1) break;
                carry_out(k);
                k++;
            }
            if (k >= k_end) break;

            int src = box_stack[k];
            int h = box_height[k];
            if (h < (int)stacks[src].size() - 1) {
                int first_above = stacks[src][h + 1];
                int dest = greedy_dest(src, k);
                move_block(first_above, dest);
            }
            carry_out(k);
        }
        return energy - start_energy;
    }
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    GLOBAL_START_TIME = std::chrono::steady_clock::now();

    int N, M;
    std::cin >> N >> M;

    std::vector<std::vector<int>> initial_stacks(M, std::vector<int>(N / M));
    for (int i = 0; i < M; i++)
        for (int j = 0; j < N / M; j++) {
            std::cin >> initial_stacks[i][j];
            initial_stacks[i][j]--;
        }

    std::mt19937 rng(42);

    long long best_energy = LLONG_MAX;
    std::vector<std::pair<int,int>> best_ops;

    // Approach: rolling lookahead greedy with noise-based restarts
    // For each target k, try all M-1 destinations, simulate forward LOOKAHEAD steps
    // greedily for each, pick the dest with lowest total lookahead cost

    auto solve = [&](double noise, int lookahead_depth) -> long long {
        State st;
        st.init(N, M, initial_stacks, true);
        int k = 0;

        while (k < N) {
            while (k < N) {
                int src = st.box_stack[k];
                int h = st.box_height[k];
                if (h != (int)st.stacks[src].size() - 1) break;
                st.carry_out(k);
                k++;
            }
            if (k >= N) break;

            int src = st.box_stack[k];
            int h = st.box_height[k];

            if (h == (int)st.stacks[src].size() - 1) {
                st.carry_out(k);
                k++;
                continue;
            }

            int first_above = st.stacks[src][h + 1];

            int best_dest = -1;
            double best_cost = 1e18;

            // Determine actual lookahead based on remaining time
            int actual_lookahead = lookahead_depth;
            if (elapsed() > TIME_LIMIT * 0.9) actual_lookahead = 0;
            else if (elapsed() > TIME_LIMIT * 0.7) actual_lookahead = std::min(actual_lookahead, 2);

            for (int d = 0; d < M; d++) {
                if (d == src) continue;

                double cost = 0;
                if (actual_lookahead > 0 && noise == 0) {
                    // Simulate: move block to d, then extract next few targets greedily
                    State sim = st.copy_no_ops();
                    sim.move_block(first_above, d);
                    sim.carry_out(k);

                    int sim_end = std::min(N, k + 1 + actual_lookahead);
                    long long future_cost = sim.simulate_greedy(k + 1, sim_end);
                    cost = (double)(sim.energy - st.energy - future_cost) + future_cost; // total
                    // Actually: cost of move to d + cost of future moves
                    int pile_size = (int)st.stacks[src].size() - 1 - h;
                    cost = (pile_size + 1) + (double)future_cost;
                } else {
                    // Heuristic evaluation
                    int pile_size = (int)st.stacks[src].size() - 1 - h;
                    cost = pile_size + 1;

                    // Penalty for burying soon-needed boxes
                    for (int look = k + 1; look < std::min(N, k + 20); look++) {
                        int ls = st.box_stack[look];
                        int lh = st.box_height[look];
                        double urgency = 20.0 / (look - k);

                        if (ls == src && lh > h) {
                            // This box is in the pile being moved
                            int new_h = (int)st.stacks[d].size() + (lh - h - 1);
                            int new_stack_size = (int)st.stacks[d].size() + pile_size;
                            int above = new_stack_size - 1 - new_h;
                            if (above > 0) cost += (above + 1) * urgency * 0.3;
                        } else if (ls == d) {
                            // Already in dest, will be buried further
                            int above = (int)st.stacks[d].size() + pile_size - 1 - lh;
                            if (above > 0) cost += (above + 1) * urgency * 0.3;
                        }
                    }

                    if (st.stacks[d].empty()) cost -= 5.0;
                    cost += st.stacks[d].size() * 0.5;
                }

                if (noise > 0) {
                    cost += std::uniform_real_distribution<double>(-noise, noise)(rng);
                }

                if (cost < best_cost) {
                    best_cost = cost;
                    best_dest = d;
                }
            }

            st.move_block(first_above, best_dest);
            st.carry_out(k);
            k++;
        }

        if (st.energy < best_energy) {
            best_energy = st.energy;
            best_ops = st.ops;
        }
        return st.energy;
    };

    // First: deterministic run with lookahead
    solve(0.0, 5);

    // Then: noise-based restarts (faster, heuristic only)
    while (elapsed() < TIME_LIMIT) {
        double noise = std::uniform_real_distribution<double>(2.0, 20.0)(rng);
        solve(noise, 0);
    }

    for (const auto& op : best_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }
    return 0;
}
