    std::array<int, N_CONST> best_plan = make_greedy_plan(0.0);
    long long best_energy = evaluate_full(initial_stacks, best_plan);

    for (int i = 0; i < 30 && elapsed() < 0.15; i++) {
        double noise = std::uniform_real_distribution<double>(2.0, 20.0)(rng);
        auto p = make_greedy_plan(noise);
        long long e = evaluate_full(initial_stacks, p);
        if (e < best_energy) {
            best_energy = e;
            best_plan = p;
        }
    }

    // SA phase with full re-evaluation (fast due to small N=200)
    std::array<int, N_CONST> current_plan = best_plan;
    long long current_energy = best_energy;

    double T_init = 60.0;
    double T_final = 0.05;
    double sa_start = elapsed();
    double sa_budget = TIME_LIMIT - sa_start - 0.02;

    while (true) {
        double now = elapsed();
        if (now >= TIME_LIMIT - 0.02) break;

        double progress = (now - sa_start) / sa_budget;
        if (progress > 1.0) break;
        double T = T_init * std::pow(T_final / T_init, progress);

        std::array<int, N_CONST> new_plan = current_plan;

        int change_start = N_CONST;
        double r = std::uniform_real_distribution<double>(0, 1)(rng);

        if (r < 0.5) {
            // Single point change
            int idx = std::uniform_int_distribution<int>(0, N_CONST - 1)(rng);
            new_plan[idx] = std::uniform_int_distribution<int>(0, M_CONST - 1)(rng);
            change_start = idx;
        } else if (r < 0.85) {
            // Block change (2-12 consecutive)
            int idx = std::uniform_int_distribution<int>(0, N_CONST - 1)(rng);
            int len = std::uniform_int_distribution<int>(2, 12)(rng);
            change_start = idx;
            for (int i = 0; i < len && idx + i < N_CONST; i++) {
                new_plan[idx + i] = std::uniform_int_distribution<int>(0, M_CONST - 1)(rng);
            }
        } else {
            // Swap two entries
            int i1 = std::uniform_int_distribution<int>(0, N_CONST - 1)(rng);
            int i2 = std::uniform_int_distribution<int>(0, N_CONST - 1)(rng);
            std::swap(new_plan[i1], new_plan[i2]);
            change_start = std::min(i1, i2);
        }

        // Evaluate from change_start
        FastState st;
        simulate_prefix(initial_stacks, new_plan, change_start, st);
        long long new_energy = st.run_from(new_plan, change_start);

        if (new_energy < current_energy) {
            current_energy = new_energy;
            current_plan = new_plan;
            if (new_energy < best_energy) {
                best_energy = new_energy;
                best_plan = new_plan;
            }
        } else {
            double delta = new_energy - current_energy;
            if (std::uniform_real_distribution<double>(0, 1)(rng) < std::exp(-delta / T)) {
                current_energy = new_energy;
                current_plan = new_plan;
            }
        }
    }

    // Output
    std::vector<std::pair<int,int>> ops;
    generate_ops(initial_stacks, best_plan, ops);
    for (const auto& op : ops) {
        std::cout << op.first << " " << op.second << "\n";
    }
    return 0;
}
