// Fast xoshiro256** RNG
struct Xoshiro {
    uint64_t s[4];

    Xoshiro(uint64_t seed) {
        s[0] = seed;
        s[1] = seed * 6364136223846793005ULL + 1;
        s[2] = s[1] * 6364136223846793005ULL + 1;
        s[3] = s[2] * 6364136223846793005ULL + 1;
        for (int i = 0; i < 8; i++) next();
    }

    uint64_t next() {
        uint64_t result = ((s[1] * 5) << 7 | (s[1] * 5) >> 57) * 9;
        uint64_t t = s[1] << 17;
        s[2] ^= s[0]; s[3] ^= s[1]; s[1] ^= s[2]; s[0] ^= s[3];
        s[2] ^= t;
        s[3] = (s[3] << 45) | (s[3] >> 19);
        return result;
    }

    int next_int(int n) { return (int)(next() % (uint64_t)n); }
    double next_double() { return (next() >> 11) * (1.0 / (1ULL << 53)); }
