            current_energy = new_energy;
            std::copy(new_plan, new_plan + N_CONST, current_plan);
            if (new_energy < best_energy) {
                best_energy = new_energy;
                std::copy(new_plan, new_plan + N_CONST, best_plan);
            }
        } else {
            if (std::uniform_real_distribution<double>(0, 1)(rng) < std::exp(-(double)delta / T)) {
                current_energy = new_energy;
                std::copy(new_plan, new_plan + N_CONST, current_plan);
            }
        }
    }

    // Output
