    }

    ops.clear();
    for (int k = 0; k < N_CONST; k++) {
        int src = box_stack[k];
        int h = box_height[k];
        int src_size = stack_top[src];
        if (h < src_size - 1) {
            int first_above = stack_data[src][h + 1];
            int d = plan[k];
            if (d == src) d = (src + 1) % M_CONST;
            int dest_h = stack_top[d];
            for (int i = h + 1; i < src_size; i++) {
                int b = stack_data[src][i];
                stack_data[d][dest_h] = b;
                box_stack[b] = d;
                box_height[b] = dest_h;
                dest_h++;
            }
            stack_top[d] = dest_h;
            stack_top[src] = h + 1;
            ops.push_back({first_above + 1, d + 1});
        }
        stack_top[src]--;
        ops.push_back({k + 1, 0});
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    GLOBAL_START_TIME = std::chrono::steady_clock::now();

    int N, M;
    std::cin >> N >> M;

    std::vector<std::vector<int>> initial_stacks(M);
    for (int i = 0; i < M; i++) {
        initial_stacks[i].resize(N / M);
        for (int j = 0; j < N / M; j++) {
            std::cin >> initial_stacks[i][j];
            initial_stacks[i][j]--;
        }
    }

    std::mt19937 rng(std::chrono::steady_clock::now().time_since_epoch().count());

    // Greedy plan generation
    auto make_greedy_plan = [&](int plan[N_CONST], double noise) {
        int box_stack[N_CONST], box_height[N_CONST];
        int stack_data[M_CONST][N_CONST + 10];
        int stack_top[M_CONST];

        for (int i = 0; i < M_CONST; i++) {
            stack_top[i] = (int)initial_stacks[i].size();
            for (int j = 0; j < stack_top[i]; j++) {
                int b = initial_stacks[i][j];
                stack_data[i][j] = b;
                box_stack[b] = i;
                box_height[b] = j;
            }
        }

        for (int k = 0; k < N_CONST; k++) {
            int src = box_stack[k];
            int h = box_height[k];
            int src_size = stack_top[src];

            if (h == src_size - 1) {
                plan[k] = src;
                stack_top[src]--;
                continue;
            }

            int pile_size = src_size - 1 - h;
            int best_d = (src + 1) % M_CONST;
            double best_score = 1e18;

            for (int d = 0; d < M_CONST; d++) {
                if (d == src) continue;
                double score = pile_size + 1;

                for (int look = k + 1; look < std::min(N_CONST, k + 30); look++) {
                    double weight = 1.0 / (look - k);
                    int ls = box_stack[look];
                    int lh = box_height[look];

                    if (ls == src && lh > h) {
                        int new_h = stack_top[d] + (lh - h - 1);
                        int new_size = stack_top[d] + pile_size;
                        int above = new_size - 1 - new_h;
                        if (above > 0) score += (above + 1) * weight;
                    } else if (ls == d) {
                        int above = stack_top[d] + pile_size - 1 - lh;
                        if (above > 0) score += (above + 1) * weight;
                    }
                }

                if (stack_top[d] == 0) score -= 3.0;
                score += stack_top[d] * 0.2;

                if (noise > 0) {
                    std::uniform_real_distribution<double> ndist(-noise, noise);
                    score += ndist(rng);
                }

                if (score < best_score) {
                    best_score = score;
                    best_d = d;
                }
            }

            plan[k] = best_d;
            int dest_h = stack_top[best_d];
            for (int i = h + 1; i < src_size; i++) {
                int b = stack_data[src][i];
                stack_data[best_d][dest_h] = b;
                box_stack[b] = best_d;
                box_height[b] = dest_h;
                dest_h++;
            }
            stack_top[best_d] = dest_h;
            stack_top[src] = h + 1;
            stack_top[src]--;
        }
    };

    int best_plan[N_CONST];
    int current_plan[N_CONST];
    int new_plan[N_CONST];

    make_greedy_plan(best_plan, 0.0);
    long long best_energy = evaluate_plan(initial_stacks, best_plan);

    // Noisy greedy restarts
    for (int i = 0; i < 80 && elapsed() < 0.20; i++) {
        double noise = 2.0 + std::uniform_real_distribution<double>(0, 18)(rng);
        int tmp_plan[N_CONST];
        make_greedy_plan(tmp_plan, noise);
        long long e = evaluate_plan(initial_stacks, tmp_plan);
        if (e < best_energy) {
            best_energy = e;
            std::copy(tmp_plan, tmp_plan + N_CONST, best_plan);
        }
    }

    // SA with periodic restarts from best
    std::copy(best_plan, best_plan + N_CONST, current_plan);
    long long current_energy = best_energy;

    double T_init = 50.0;
    double T_final = 0.05;
    double sa_start = elapsed();
    double sa_budget = TIME_LIMIT - sa_start - 0.02;

    int no_improve_count = 0;
    const int RESTART_THRESHOLD = 3000;

    while (true) {
        double now = elapsed();
        if (now >= TIME_LIMIT - 0.02) break;

        double progress = (now - sa_start) / sa_budget;
        if (progress > 1.0) break;
        double T = T_init * std::pow(T_final / T_init, progress);

        // Restart from best if stuck
        if (no_improve_count > RESTART_THRESHOLD) {
            std::copy(best_plan, best_plan + N_CONST, current_plan);
            current_energy = best_energy;
            no_improve_count = 0;
        }

        std::copy(current_plan, current_plan + N_CONST, new_plan);

        int r = std::uniform_int_distribution<int>(0, 99)(rng);
        if (r < 50) {
            int idx = std::uniform_int_distribution<int>(0, N_CONST - 1)(rng);
            new_plan[idx] = std::uniform_int_distribution<int>(0, M_CONST - 1)(rng);
        } else if (r < 85) {
            int idx = std::uniform_int_distribution<int>(0, N_CONST - 1)(rng);
            int len = std::uniform_int_distribution<int>(2, 14)(rng);
            int end = std::min(N_CONST, idx + len);
            for (int i = idx; i < end; i++) {
                new_plan[i] = std::uniform_int_distribution<int>(0, M_CONST - 1)(rng);
            }
        } else {
            int i1 = std::uniform_int_distribution<int>(0, N_CONST - 1)(rng);
            int i2 = std::uniform_int_distribution<int>(0, N_CONST - 1)(rng);
            std::swap(new_plan[i1], new_plan[i2]);
        }

        long long new_energy = evaluate_plan(initial_stacks, new_plan);
        long long delta = new_energy - current_energy;

        if (delta <= 0) {
            current_energy = new_energy;
            std::copy(new_plan, new_plan + N_CONST, current_plan);
            if (new_energy < best_energy) {
                best_energy = new_energy;
                std::copy(new_plan, new_plan + N_CONST, best_plan);
                no_improve_count = 0;
            } else {
                no_improve_count++;
            }
        } else {
            if (std::uniform_real_distribution<double>(0, 1)(rng) < std::exp(-(double)delta / T)) {
                current_energy = new_energy;
                std::copy(new_plan, new_plan + N_CONST, current_plan);
            }
            no_improve_count++;
        }
    }

    // Output
    std::vector<std::pair<int,int>> ops;
    generate_ops(initial_stacks, best_plan, ops);
    for (const auto& op : ops) {
        std::cout << op.first << " " << op.second << "\n";
    }
    return 0;
}
